Output from "dovecot -n". Domain have been modified.

% dovecot -n
# 2.3.2.1 (0719df592): /usr/local/etc/dovecot/dovecot.conf
# Pigeonhole version 0.5.2 (7704de5e)
/usr/local/libexec/dovecot/managesieve: Undefined symbol "i_stream_read_memarea"
doveconf: Error: managesieve-login: dump-capability process returned 1
# OS: FreeBSD 10.4-RELEASE-p9 amd64
# Hostname: mail.example.com
auth_mechanisms = plain login
first_valid_uid = 125
hostname = mail.example.com
listen = *
log_path = /var/log/dovecot
mail_plugins = zlib
mail_privileged_group = postfix
mail_temp_dir = /var/db/dovecot
namespace compat {
  hidden = yes
  inbox = no
  list = no
  location =
  prefix = INBOX.
  separator = .
  type = private
}
namespace inbox {
  inbox = yes
  location =
  mailbox Drafts {
    special_use = \Drafts
  }
  mailbox "Sent Items" {
    special_use = \Sent
  }
  mailbox Spam {
    special_use = \Junk
  }
  mailbox Trash {
    special_use = \Trash
  }
  prefix =
  separator = .
  type = private
}
passdb {
  args = /usr/local/etc/dovecot/dovecot-sql.conf.ext
  driver = sql
}
plugin {
  fts = squat
  fts_squat = partial=4 full=10
  sieve = ~/.dovecot.sieve
  sieve_dir = ~/sieve
}
postmaster_address = postmaster@example.com
protocols = imap pop3 lmtp sieve
service auth-worker {
  user = $default_internal_user
}
service auth {
  unix_listener /home/mail/postfix/private/dovecot-auth {
    group = postfix
    mode = 0660
    user = postfix
  }
}
service lmtp {
  executable = lmtp -L
  unix_listener /home/mail/postfix/private/dovecot-lmtp {
    group = postfix
    mode = 0660
    user = postfix
  }
}
ssl_cert = </etc/ssl/example.com-chained.crt
ssl_dh =  # hidden, use -P to show it
ssl_key =  # hidden, use -P to show it
userdb {
  args = /usr/local/etc/dovecot/dovecot-sql.conf.ext
  driver = sql
}
protocol lmtp {
  log_path = /var/log/dovecot-deliver
  mail_plugins = zlib sieve
}
protocol lda {
  mail_plugins = zlib sieve
}
protocol imap {
  mail_max_userip_connections = 30
  mail_plugins = zlib imap_zlib
}
